// Gyroid-lattice pen/brush holder vase
// - SOLID flat base disk (z=0), SOLID rim ring at top
// - OPEN gyroid lattice wall between, welded to base + rim
// Two-tone: teal lattice body, gold trim (base + rim).
const { voxels, sdf } = api;
const v = voxels();

const BODY = '#1f9e8a'; // deep teal lattice
const TRIM = '#e6b54a'; // warm gold base + rim

// --- dimensions (world units ~ mm) ---
const H        = 70;   // total height
const R_OUT    = 22;   // outer radius
const WALL     = 4;    // wall thickness (annulus)
const R_IN     = R_OUT - WALL;
const BASE_H   = 6;    // solid base disk height
const RIM_H    = 5;    // solid rim ring height
const CELL     = 19;   // gyroid cell size (bigger -> bolder holes)
const THICK    = 0.46; // gyroid wall (field units) -> open lattice w/ solid struts

// build everything centered on origin in Z then we'll have z from 0..H
const zc = H / 2;

// outer / inner cylinders for the annulus, full height
const outerCyl = sdf.cylinder(R_OUT, H).translate(0, 0, zc);
const innerCyl = sdf.cylinder(R_IN,  H + 4).translate(0, 0, zc);
const annulus  = outerCyl.subtract(innerCyl);

// gyroid wall = infinite gyroid intersected with the annulus
const wall = sdf.gyroid(CELL, THICK).intersect(annulus).label('body');

// solid base disk
const base = sdf.cylinder(R_OUT, BASE_H).translate(0, 0, BASE_H / 2).label('trim');

// solid rim ring (annulus shell at top, hollow center so pens go in)
const rimOuter = sdf.cylinder(R_OUT, RIM_H).translate(0, 0, H - RIM_H / 2);
const rimInner = sdf.cylinder(R_IN,  RIM_H + 4).translate(0, 0, H - RIM_H / 2);
const rim = rimOuter.subtract(rimInner).label('trim');

const model = wall.union(base).union(rim);

v.sdf(model, {
  res: 1,
  color: BODY,
  colors: { body: BODY, trim: TRIM },
  bounds: { min: [-R_OUT - 1, -R_OUT - 1, -1], max: [R_OUT + 1, R_OUT + 1, H + 1] },
});

return v;
